class Solution:
    def __init__(self, nums: List[int]):
        self.orig = nums[:]
        self.arr = nums[:]
    def reset(self) -> List[int]:
        self.arr = self.orig[:]
        return self.arr
    def shuffle(self) -> List[int]:
        a = self.arr[:]
        for i in range(len(a)-1, 0, -1):
            j = random.randint(0, i)
            a[i], a[j] = a[j], a[i]
        self.arr = a
        return a

