class Solution {
    vector<int> orig, arr;
public:
    Solution(vector<int>& nums) : orig(nums), arr(nums) {}
    vector<int> reset() { arr = orig; return arr; }
    vector<int> shuffle() {
        for (int i = arr.size()-1; i > 0; i--) {
            int j = rand() % (i+1);
            swap(arr[i], arr[j]);
        }
        return arr;
    }
};

